Here's an updated version of the `BaseRepository` class that allows you to find by a dynamic field. We'll use reflection to achieve this.

```csharp
public abstract class BaseRepository<T> : IRepository<T> where T : class
{
    private readonly DbContext _context;
    private readonly DbSet<T> _dbSet;

    protected BaseRepository(DbContext context)
    {
        _context = context;
        _dbSet = context.Set<T>();
    }

    public virtual async Task<IEnumerable<T>> GetAllAsync()
    {
        return await _dbSet.ToListAsync();
    }

    public virtual async Task<T> GetByIdAsync(object id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<T> GetByDynamicFieldAsync(string fieldName, object value)
    {
        // Use reflection to get the property info of the field
        var propertyInfo = typeof(T).GetProperty(fieldName);

        if (propertyInfo == null)
        {
            throw new ArgumentException($"Property {fieldName} does not exist on type {typeof(T).Name}");
        }

        // Use the property info to get the value from the database
        return await _dbSet.FirstOrDefaultAsync(x => propertyInfo.GetValue(x).Equals(value));
    }

